// ── Filter to last 24 hours and build aggregate stats ──────────
// Paste the full script from preprocess.md Section 2

const rows    = $input.all().map(item => item.json);
const cutoff  = new Date(Date.now() - 24 * 60 * 60 * 1000);
const recent  = rows.filter(r => r.submissionDateTime && new Date(r.submissionDateTime) >= cutoff);

if (recent.length === 0) {
  // No new complaints — signal the workflow to stop gracefully
  return [{ json: { noComplaints: true, generatedAt: new Date().toISOString() } }];
}

// ── Aggregate counts ──────────────────────────────────────────
const byCategory  = {};
const byFacility  = {};
const byPriority  = {};
const byIssueType = {};

recent.forEach(function (r) {
  const cat  = r.aiCategory    || 'unclassified';
  const fac  = r.healthFacility || 'Unknown';
  const pri  = r.priority       || 'medium';
  const type = r.issueType      || 'unspecified';

  byCategory[cat]   = (byCategory[cat]   || 0) + 1;
  byFacility[fac]   = (byFacility[fac]   || 0) + 1;
  byPriority[pri]   = (byPriority[pri]   || 0) + 1;
  byIssueType[type] = (byIssueType[type] || 0) + 1;
});

// ── Top 3 sample summaries for AI context ────────────────────
const samples = recent
  .filter(r => r.priority === 'high')
  .slice(0, 5)
  .concat(recent.filter(r => r.priority !== 'high').slice(0, 3))
  .map(r => ({
    caseNumber:    r.caseNumber,
    facility:      r.healthFacility,
    category:      r.aiCategory,
    priority:      r.priority,
    aiSummary:     r.aiSummary,
    missingFields: r.missingFields
  }));

return [{
  json: {
    totalComplaints:  recent.length,
    period:           'Last 24 hours — ' + new Date().toISOString(),
    byCategory,
    byFacility,
    byPriority,
    byIssueType,
    highPriorityCount: byPriority['high'] || 0,
    caseNumbers:      recent.map(r => r.caseNumber),
    sampleCases:      samples,
    noComplaints:     false
  }
}];
